def publish_simple_notification(topic_arn, message, notification_type='info'):
    """
    Simplified function for publishing a notification.
    Can be imported and used by other Lambda functions.
    """
    event = {
        'topic_arn': topic_arn,
        'message': message,
        'notification_type': notification_type
    }
